import { vi, describe, it, expect, beforeEach } from "vitest";
import { NextRequest } from "next/server";
import { GET as listPages, POST } from "@/app/api/cms/pages/route";
import { GET as getPage, PUT as updatePage, DELETE as deletePage } from "@/app/api/cms/pages/[id]/route";
import { getCmsRepository } from "@/features/cms/services/cms-repository";

vi.mock("@/features/cms/services/cms-repository", () => ({
  getCmsRepository: vi.fn(),
}));

vi.mock("@/features/cms/services/cms-domain", () => ({
  resolveCmsDomainFromRequest: vi.fn().mockResolvedValue({ id: "d1", domain: "localhost" }),
  getSlugsForDomain: vi.fn().mockResolvedValue([]),
  resolveCmsDomainScopeById: vi.fn(),
}));

vi.mock("@/features/observability/server", () => ({
  ErrorSystem: {
    captureException: vi.fn(),
  },
}));

describe("CMS Pages API", () => {
  const mockRepo = {
    getPages: vi.fn(),
    getPageById: vi.fn(),
    createPage: vi.fn(),
    updatePage: vi.fn(),
    deletePage: vi.fn(),
    addSlugToPage: vi.fn(),
    replacePageSlugs: vi.fn(),
  };

  beforeEach(() => {
    vi.clearAllMocks();
    (getCmsRepository as any).mockResolvedValue(mockRepo);
  });

  describe("GET /api/cms/pages", () => {
    it("should return a list of pages", async () => {
      const mockPages = [{ id: "1", name: "Page 1" }];
      mockRepo.getPages.mockResolvedValue(mockPages);

      const res = await listPages(new NextRequest("http://localhost/api/cms/pages?scope=all"));
      const data = await res.json();

      expect(res.status).toBe(200);
      expect(data).toEqual(mockPages);
      expect(mockRepo.getPages).toHaveBeenCalled();
    });
  });

  describe("GET /api/cms/pages/[id]", () => {
    it("should return a single page", async () => {
      const mockPage = { id: "123", name: "Single Page" };
      mockRepo.getPageById.mockResolvedValue(mockPage);

      const res = await getPage(new NextRequest("http://localhost"), { params: Promise.resolve({ id: "123" }) } as any);
      const data = await res.json();

      expect(res.status).toBe(200);
      expect(data).toEqual(mockPage);
    });

    it("should return 404 if page not found", async () => {
      mockRepo.getPageById.mockResolvedValue(null);
      const res = await getPage(new NextRequest("http://localhost"), { params: Promise.resolve({ id: "999" }) } as any);
      expect(res.status).toBe(404);
    });
  });

  describe("POST /api/cms/pages", () => {
    it("should create a new page", async () => {
      const pageData = { name: "New CMS Page", slugIds: ["slug-1"] };
      const createdPage = { id: "p-123", name: "New CMS Page" };
      mockRepo.createPage.mockResolvedValue(createdPage);

      const req = new NextRequest("http://localhost/api/cms/pages", {
        method: "POST",
        body: JSON.stringify(pageData),
      });

      const res = await createPage(req);
      const data = await res.json();

      expect(res.status).toBe(200);
      expect(data).toEqual(createdPage);
      expect(mockRepo.createPage).toHaveBeenCalledWith({ name: "New CMS Page" });
      expect(mockRepo.addSlugToPage).toHaveBeenCalledWith("p-123", "slug-1");
    });
  });

  describe("PUT /api/cms/pages/[id]", () => {
    it("should update a page", async () => {
      const updateData = {
        name: "Updated Page",
        slugIds: ["s1"],
        components: [{ type: "Hero", content: {} }]
      };
      const updatedPage = { id: "123", name: "Updated Page" };
      mockRepo.updatePage.mockResolvedValue(updatedPage);

      const req = new NextRequest("http://localhost", {
        method: "PUT",
        body: JSON.stringify(updateData),
      });

      const res = await updatePage(req, { params: Promise.resolve({ id: "123" }) } as any);
      const data = await res.json();

      expect(res.status).toBe(200);
      expect(data).toEqual(updatedPage);
      expect(mockRepo.updatePage).toHaveBeenCalledWith("123", expect.objectContaining({ name: "Updated Page" }));
      expect(mockRepo.replacePageSlugs).toHaveBeenCalledWith("123", ["s1"]);
    });
  });

  describe("DELETE /api/cms/pages/[id]", () => {
    it("should delete a page", async () => {
      mockRepo.deletePage.mockResolvedValue({ id: "123" });
      const res = await deletePage(new NextRequest("http://localhost"), { params: Promise.resolve({ id: "123" }) } as any);
      expect(res.status).toBe(204);
      expect(mockRepo.deletePage).toHaveBeenCalledWith("123");
    });
  });
});

import { NextRequest } from "next/server";
import { GET as GET_pages, POST } from "@/app/api/cms/pages/route";
import { GET as GET_page, PUT as PUT_page, DELETE as DELETE_page } from "@/app/api/cms/pages/[id]/route";
import { getCmsRepository } from "@/features/cms/services/cms-repository";
import type { Page } from "@/features/cms/types";

describe("CMS Pages API", () => {
  let cmsRepository: any;

  beforeEach(async () => {
    cmsRepository = await getCmsRepository();

    // Cleanup: Delete all pages and slugs
    const pages = await cmsRepository.getPages();
    for (const p of pages) {
      await cmsRepository.deletePage(p.id);
    }

    const slugs = await cmsRepository.getSlugs();
    for (const s of slugs) {
      await cmsRepository.deleteSlug(s.id);
    }

    const themes = await cmsRepository.getThemes();
    for (const t of themes) {
      await cmsRepository.deleteTheme(t.id);
    }
  });

  describe("GET /api/cms/pages", () => {
    it("should return an empty list when no pages exist", async () => {
      const res = await GET_pages(new NextRequest("http://localhost/api/cms/pages"));
      const data = await res.json();
      expect(res.status).toBe(200);
      expect(data).toEqual([]);
    });

    it("should return all pages", async () => {
      await cmsRepository.createPage({ name: "Page 1" });
      await cmsRepository.createPage({ name: "Page 2" });

      const res = await GET_pages(new NextRequest("http://localhost/api/cms/pages?scope=all"));
      const data = await res.json() as Page[];
      expect(res.status).toBe(200);
      expect(data.length).toBe(2);
      expect(data.map(p => p.name)).toContain("Page 1");
      expect(data.map(p => p.name)).toContain("Page 2");
    });
  });

  describe("CMS Slugs Type Check", () => {
    it("should correctly type a slug object", () => {
      const slug = {
        id: "s1",
        slug: "test",
        createdAt: new Date(),
        updatedAt: new Date()
      };
      expect(slug.slug).toBe("test");
    });
  });

  describe("POST /api/cms/pages", () => {
    it("should create a new page without slugs", async () => {
      const req = new NextRequest("http://localhost/api/cms/pages", {
        method: "POST",
        body: JSON.stringify({ name: "New Page" }),
      });

      const res = await POST_pages(req);
      const data = await res.json() as Page;

      expect(res.status).toBe(200);
      expect(data.name).toBe("New Page");
      expect(data.id).toBeDefined();
    });

    it("should create a new page with slugs", async () => {
      const slug1 = await cmsRepository.createSlug({ slug: "test-slug-1" });
      const slug2 = await cmsRepository.createSlug({ slug: "test-slug-2" });

      const req = new NextRequest("http://localhost/api/cms/pages", {
        method: "POST",
        body: JSON.stringify({ 
          name: "Page with Slugs",
          slugIds: [slug1.id, slug2.id]
        }),
      });

      const res = await POST_pages(req);
      const data = await res.json() as Page;

      expect(res.status).toBe(200);
      expect(data.name).toBe("Page with Slugs");

      // Verify page in repository has slugs
      const savedPage = await cmsRepository.getPageById(data.id);
      expect(savedPage.slugs.length).toBe(2);
    });

    it("should create a new page with a theme", async () => {
      const theme = await cmsRepository.createTheme({
        name: "Creation Theme",
        colors: { primary: "#000", secondary: "#fff", accent: "#f00", background: "#fff", surface: "#eee", text: "#000", muted: "#888" },
        typography: { headingFont: "Arial", bodyFont: "Arial", baseSize: 16, headingWeight: 700, bodyWeight: 400 },
        spacing: { sectionPadding: "1rem", containerMaxWidth: "1000px" }
      });

      const req = new NextRequest("http://localhost/api/cms/pages", {
        method: "POST",
        body: JSON.stringify({ 
          name: "Page with Theme",
          themeId: theme.id
        }),
      });

      const res = await POST_pages(req);
      const data = await res.json() as Page;

      expect(res.status).toBe(200);
      expect(data.name).toBe("Page with Theme");

      // Verify page in repository has the theme
      const savedPage = await cmsRepository.getPageById(data.id);
      expect(savedPage.themeId).toBe(theme.id);
    });

    it("should return 400 for invalid input", async () => {
      const req = new NextRequest("http://localhost/api/cms/pages", {
        method: "POST",
        body: JSON.stringify({ name: "" }), // Invalid: empty name
      });

      const res = await POST_pages(req);
      expect(res.status).toBe(400);
    });
  });

  describe("GET /api/cms/pages/[id]", () => {
    it("should return a page by ID", async () => {
      const page = await cmsRepository.createPage({ name: "Single Page" });

      const res = await GET_page(new NextRequest(`http://localhost/api/cms/pages/${page.id}`), { params: Promise.resolve({ id: page.id }) });
      const data = await res.json() as Page;

      expect(res.status).toBe(200);
      expect(data.id).toBe(page.id);
      expect(data.name).toBe("Single Page");
    });

    it("should return 404 for non-existent page", async () => {
      const res = await GET_page(new NextRequest("http://localhost/api/cms/pages/non-existent"), { params: Promise.resolve({ id: "non-existent" }) });
      expect(res.status).toBe(404);
    });
  });

  describe("PUT /api/cms/pages/[id]", () => {
    it("should update page basic info, components and theme", async () => {
      const page = await cmsRepository.createPage({ name: "Old Name" });
      const slug = await cmsRepository.createSlug({ slug: "updated-slug" });
      const theme = await cmsRepository.createTheme({
        name: "Page Theme",
        colors: { primary: "#000", secondary: "#fff", accent: "#f00", background: "#fff", surface: "#eee", text: "#000", muted: "#888" },
        typography: { headingFont: "Arial", bodyFont: "Arial", baseSize: 16, headingWeight: 700, bodyWeight: 400 },
        spacing: { sectionPadding: "1rem", containerMaxWidth: "1000px" }
      });

      const updatePayload = {
        name: "Updated Name",
        status: "published",
        publishedAt: new Date().toISOString(),
        seoTitle: "SEO Title",
        seoDescription: "SEO Description",
        slugIds: [slug.id],
        themeId: theme.id,
        components: [
          { type: "hero", content: { title: "Hello World" } },
          { type: "text", content: { body: "Lorem ipsum" } }
        ]
      };

      const req = new NextRequest(`http://localhost/api/cms/pages/${page.id}`, {
        method: "PUT",
        body: JSON.stringify(updatePayload),
      });

      const res = await PUT_page(req, { params: Promise.resolve({ id: page.id }) });
      const data = await res.json() as Page;

      expect(res.status).toBe(200);
      expect(data.name).toBe("Updated Name");
      expect(data.status).toBe("published");
      expect(data.seoTitle).toBe("SEO Title");

      // Verify in repository
      const updatedPage = await cmsRepository.getPageById(page.id);
      expect(updatedPage.components.length).toBe(2);
      expect(updatedPage.slugs.length).toBe(1);
      expect(updatedPage.slugs[0].slug.slug).toBe("updated-slug");
      expect(updatedPage.themeId).toBe(theme.id);
    });

    it("should return 404 when updating non-existent page", async () => {
      const req = new NextRequest("http://localhost/api/cms/pages/non-existent", {
        method: "PUT",
        body: JSON.stringify({ 
          name: "Non-existent",
          slugIds: [],
          components: []
        }),
      });

      const res = await PUT_page(req, { params: Promise.resolve({ id: "non-existent" }) });
      expect(res.status).toBe(404);
    });
  });

  describe("DELETE /api/cms/pages/[id]", () => {
    it("should delete a page", async () => {
      const page = await cmsRepository.createPage({ name: "To Delete" });

      const req = new NextRequest(`http://localhost/api/cms/pages/${page.id}`, {
        method: "DELETE",
      });

      const res = await DELETE_page(req, { params: Promise.resolve({ id: page.id }) });
      expect(res.status).toBe(204);

      const deletedPage = await cmsRepository.getPageById(page.id);
      expect(deletedPage).toBeNull();
    });
  });
});

import { GET as GET_NOTES, POST } from "@/app/api/notes/route";
import {
  GET as GET_NOTE,
  PATCH as PATCH_NOTE,
  DELETE as DELETE_NOTE,
} from "@/app/api/notes/[id]/route";
import prisma from "@/shared/lib/db/prisma";
import { NextRequest } from "next/server";
import {
  Note,
  Tag,
  Category,
  NoteTag,
  NoteCategory,
  NoteRelation,
} from "@prisma/client";

type NoteWithRelations = Note & {
  tags: (NoteTag & { tag: Tag })[];
  categories: (NoteCategory & { category: Category })[];
  relationsFrom: (NoteRelation & { targetNote: Note })[];
};

const createTag = (name: string) => prisma.tag.create({ data: { name } });
const createCategory = (name: string, parentId?: string | null) =>
  prisma.category.create({ data: { name, parentId: parentId ?? null } });

const createNote = async (data: {
  title: string;
  content: string;
  isPinned?: boolean;
  isArchived?: boolean;
  tagIds?: string[];
  categoryIds?: string[];
  relatedNoteIds?: string[];
}) => {
  const { tagIds = [], categoryIds = [], relatedNoteIds = [], ...rest } = data;
  return prisma.note.create({
    data: {
      ...rest,
      tags: {
        create: tagIds.map((tagId) => ({ tag: { connect: { id: tagId } } })),
      },
      categories: {
        create: categoryIds.map((categoryId) => ({
          category: { connect: { id: categoryId } },
        })),
      },
      relationsFrom: {
        create: relatedNoteIds.map((targetNoteId) => ({
          targetNote: { connect: { id: targetNoteId } },
        })),
      },
    },
  });
};

describe("Notes API", () => {
  beforeEach(async () => {
    await prisma.noteRelation.deleteMany({});
    await prisma.noteTag.deleteMany({});
    await prisma.noteCategory.deleteMany({});
    await prisma.note.deleteMany({});
    await prisma.tag.deleteMany({});
    await prisma.category.deleteMany({});
  });

  afterAll(async () => {
    await prisma.$disconnect();
  });

  it("returns notes with relations", async () => {
    const tag = await createTag("Work");
    const category = await createCategory("Projects");
    await createNote({
      title: "Alpha",
      content: "First note",
      isPinned: true,
      tagIds: [tag.id],
      categoryIds: [category.id],
    });

    const res = await GET_NOTES(new NextRequest("http://localhost/api/notes"));
    const notes = (await res.json()) as NoteWithRelations[];

    expect(res.status).toBe(200);
    expect(notes).toHaveLength(1);
    expect(notes[0]!.tags[0]!.tag.name).toBe("Work");
    expect(notes[0]!.categories[0]!.category.name).toBe("Projects");
  });

  it("filters notes by search scope and flags", async () => {
    await createNote({ title: "Alpha", content: "Bravo", isPinned: true });
    await createNote({ title: "Gamma", content: "Alpha", isArchived: true });

    const res = await GET_NOTES(
      new NextRequest(
        "http://localhost/api/notes?search=Alpha&searchScope=title&isPinned=true"
      )
    );
    const notes = (await res.json()) as NoteWithRelations[];

    expect(res.status).toBe(200);
    expect(notes).toHaveLength(1);
    expect(notes[0]!.title).toBe("Alpha");
  });

  it("filters notes by tags and categories", async () => {
    const tag = await createTag("Urgent");
    const category = await createCategory("Inbox");
    await createNote({
      title: "With relations",
      content: "Tagged and categorized",
      tagIds: [tag.id],
      categoryIds: [category.id],
    });
    await createNote({ title: "Other", content: "No relations" });

    const res = await GET_NOTES(
      new NextRequest(
        `http://localhost/api/notes?tagIds=${tag.id}&categoryIds=${category.id}`
      )
    );
    const notes = (await res.json()) as NoteWithRelations[];

    expect(res.status).toBe(200);
    expect(notes).toHaveLength(1);
    expect(notes[0]!.title).toBe("With relations");
  });

  it("creates a note with tags and categories", async () => {
    const tag = await createTag("Personal");
    const category = await createCategory("Home");

    const res = await POST_NOTES(
      new NextRequest("http://localhost/api/notes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title: "New Note",
          content: "Created via API",
          tagIds: [tag.id],
          categoryIds: [category.id],
        }),
      })
    );
    const note = (await res.json()) as NoteWithRelations;

    expect(res.status).toBe(201);
    expect(note.tags[0]!.tag.name).toBe("Personal");
    expect(note.categories[0]!.category.name).toBe("Home");
  });

  it("rejects note creation without title/content", async () => {
    const res = await POST_NOTES(
      new NextRequest("http://localhost/api/notes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: "", content: "" }),
      })
    );

    expect(res.status).toBe(400);
  });

  it("fetches a note by id and returns 404 when missing", async () => {
    const note = await createNote({ title: "Lookup", content: "By id" });

    const res = await GET_NOTE(new NextRequest("http://localhost/api/notes/x"), {
      params: Promise.resolve({ id: note.id }),
    });
    const data = (await res.json()) as { id: string };

    expect(res.status).toBe(200);
    expect(data.id).toBe(note.id);

    const missing = await GET_NOTE(new NextRequest("http://localhost/api/notes/y"), {
      params: Promise.resolve({ id: "missing-id" }),
    });
    expect(missing.status).toBe(404);
  });

  it("updates a note with new relations", async () => {
    const tag1 = await createTag("Old");
    const tag2 = await createTag("New");
    const category1 = await createCategory("Old Cat");
    const category2 = await createCategory("New Cat");
    const related = await createNote({
      title: "Related",
      content: "Target note",
    });
    const note = await createNote({
      title: "Original",
      content: "Content",
      tagIds: [tag1.id],
      categoryIds: [category1.id],
    });

    const res = await PATCH_NOTE(
      new NextRequest(`http://localhost/api/notes/${note.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title: "Updated",
          tagIds: [tag2.id],
          categoryIds: [category2.id],
          relatedNoteIds: [related.id],
        }),
      }),
      { params: Promise.resolve({ id: note.id }) }
    );
    const data = (await res.json()) as NoteWithRelations;

    expect(res.status).toBe(200);
    expect(data.title).toBe("Updated");
    expect(data.tags[0]!.tag.id).toBe(tag2.id);
    expect(data.categories[0]!.category.id).toBe(category2.id);
    expect(data.relationsFrom[0]!.targetNote.id).toBe(related.id);
  });

  it("deletes a note", async () => {
    const note = await createNote({ title: "Delete me", content: "Soon" });

    const res = await DELETE_NOTE(
      new NextRequest(`http://localhost/api/notes/${note.id}`, {
        method: "DELETE",
      }),
      { params: Promise.resolve({ id: note.id }) }
    );

    expect(res.status).toBe(200);
    const remaining = await prisma.note.findUnique({ where: { id: note.id } });
    expect(remaining).toBeNull();
  });
});

import pty from "node-pty";

const shell = process.env.SHELL || "/bin/zsh";

// Run gemini via the shell so PATH/aliases work
const p = pty.spawn(shell, ["-lc", "gemini"], {
  name: "xterm-256color",
  cols: process.stdout.columns ?? 120,
  rows: process.stdout.rows ?? 40,
  cwd: process.cwd(),
  env: process.env,
});

p.onData((data) => {
  process.stdout.write(data);

  if (data.includes("We are currently experiencing high demand")) {
    // Usually "1" selects Keep trying, then Enter confirms
    p.write("1\r");
  }
});

process.on("SIGINT", () => p.kill("SIGINT"));

import { readdirSync } from "fs";
import { dirname, join } from "path";
import { fileURLToPath } from "url";
import { FlatCompat } from "@eslint/eslintrc";
import importPlugin from "eslint-plugin-import";
import nextCoreWebVitals from "eslint-config-next/core-web-vitals";
import tsParser from "@typescript-eslint/parser";
import tsPlugin from "@typescript-eslint/eslint-plugin";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const compat = new FlatCompat({
  baseDirectory: __dirname,
});

const featureNames = readdirSync(join(__dirname, "src", "features"), {
  withFileTypes: true,
})
  .filter((entry) => entry.isDirectory())
  .map((entry) => entry.name);

const sharedUiRestrictions = [
  {
    group: ["@/shared/ui/*/**", "@/shared/ui/!(index)"],
    message: "Import shared UI components from the central '@/shared/ui' index instead of direct file paths.",
  },
];

const sharedUiPathRestrictions = [];

const buildRestrictedImportsRule = (extraPatterns = [], extraPaths = []) => [
  "error",
  {
    paths: [...sharedUiPathRestrictions, ...extraPaths],
    patterns: [...sharedUiRestrictions, ...extraPatterns],
  },
];

const featureBaseRestrictions = [
  {
    group: ["@/app/**"],
    message: "Features must not import from app.",
  },
];

const commonRestrictedSyntax = [
  {
    selector:
      "Property[key.name='_id'] > ObjectExpression > Property[key.name='$in'] > .value:not(TSAsExpression, CallExpression)",
    message:
      "MongoDB _id with $in detected. Ensure values are ObjectIds or the collection is explicitly typed (e.g. collection<{_id: string}>) to avoid TypeScript errors. Use 'as any' only if you are sure the DB uses string IDs.",
  },
  {
    selector:
      "BinaryExpression[operator='instanceof'][right.name='DOMException']",
    message:
      "Use 'isAbortError(error)' or check 'error.name === \"AbortError\"' instead of 'instanceof DOMException' for better cross-environment compatibility.",
  },
  {
    selector:
      "CallExpression[callee.object.name='z'][callee.property.name='unknown']",
    message:
      "Avoid using z.unknown() in Zod schemas. Prefer more specific types like z.record(z.string(), z.unknown()) or z.object({}) to maintain type safety when assigning validated data to typed interfaces.",
  },
];

const layerBoundaryConfigs = [
  {
    files: ["src/**/*.{ts,tsx,js,jsx}"],
    rules: {
      "no-restricted-imports": buildRestrictedImportsRule(),
      "import/no-restricted-paths": [
        "error",
        {
          zones: [
            {
              target: "./src/shared",
              from: "./src/features",
              message: "Shared layer must not import from features.",
            },
            {
              target: "./src/shared",
              from: "./src/app",
              message: "Shared layer must not import from app.",
            },
            {
              target: "./src/features",
              from: "./src/app",
              message: "Features must not import from app.",
            },
          ],
        },
      ],
    },
  },
  {
    files: ["src/app/**/*.{ts,tsx,js,jsx}"],
    rules: {
      "no-restricted-imports": buildRestrictedImportsRule([
        {
          group: [
            "@/features/*/!(server)",
            "@/features/*/!(server)/**",
            "@/features/*/server/**",
          ],
          message:
            "Import feature public APIs only (use '@/features/<name>' or '@/features/<name>/server').",
        },
      ]),
    },
  },
  {
    files: ["src/shared/**/*.{ts,tsx,js,jsx}"],
    rules: {
      "no-restricted-imports": buildRestrictedImportsRule([
        {
          group: ["@/features/**"],
          message: "Shared layer must not import from features.",
        },
        {
          group: ["@/app/**"],
          message: "Shared layer must not import from app.",
        },
      ]),
    },
  },
