    const noteTags: Prisma.NoteTagCreateManyInput[] = [];
    const noteTagKeys = new Set<string>();
    notes.forEach((note) => {
      note.tags.forEach((tag) => {
        const key = `${note.id}::${tag.tagId}`;
        if (noteTagKeys.has(key)) return;
        noteTagKeys.add(key);
        noteTags.push({
          noteId: note.id,
          tagId: tag.tagId,
          assignedAt: tag.assignedAt ?? note.createdAt,
