"use client";

import { useQueries, useQuery } from "@tanstack/react-query";
import { useMemo } from "react";

// Hook for dependent queries - execute queries in sequence
export function useDependentQueries<T1, T2, T3>(
  firstQuery: { queryKey: unknown[]; queryFn: () => Promise<T1>; enabled?: boolean },
  secondQuery: { queryKey: unknown[]; queryFn: (data: T1) => Promise<T2> },
  thirdQuery?: { queryKey: unknown[]; queryFn: (data: T2) => Promise<T3> }
): {
  first: any;
  second: any;
  third: any;
  isLoading: boolean;
  isError: boolean;
  error: Error | null;
} {
  const first = useQuery({
    queryKey: firstQuery.queryKey,
    queryFn: firstQuery.queryFn,
    enabled: firstQuery.enabled !== false,
  });

  const second = useQuery({
    queryKey: [...secondQuery.queryKey, first.data],
    queryFn: () => secondQuery.queryFn(first.data!),
    enabled: !!first.data && first.isSuccess,
  });

  const third = useQuery({
    queryKey: thirdQuery ? [...thirdQuery.queryKey, second.data] : ["__empty_third__"],
    queryFn: thirdQuery ? () => thirdQuery.queryFn(second.data!) : () => Promise.resolve(null as any),
    enabled: !!thirdQuery && !!second.data && second.isSuccess,
  });

  return {
    first,
    second,
    third: thirdQuery ? third : null,
    isLoading: Boolean(first.isLoading || (first.isSuccess && second.isLoading) || 
               (thirdQuery && second.isSuccess && third.isLoading)),
    isError: Boolean(first.isError || second.isError || (thirdQuery && third.isError)),
    error: (first.error || second.error || (thirdQuery && third.error)) as Error | null,
  };
}

// Hook for parallel queries with combined loading state
export function useParallelQueries<T extends Record<string, any>>(
  queries: {
    [K in keyof T]: {
      queryKey: unknown[];
      queryFn: () => Promise<T[K]>;
      enabled?: boolean;
    };
  }
): {
  data: T;
  isLoading: boolean;
  isError: boolean;
  errors: Error[];
  isSuccess: boolean;
  refetch: () => Promise<unknown[]>;
} {
  const queryResults = useQueries({
    queries: Object.entries(queries).map(([, config]) => ({
      queryKey: config.queryKey,
      queryFn: config.queryFn,
      enabled: config.enabled !== false,
    })),
  });

  const results = useMemo(() => {
    const data = {} as T;
    const keys = Object.keys(queries);

    queryResults.forEach((result, index) => {
      const key = keys[index] as keyof T;
      data[key] = result.data as T[keyof T];
    });

    return {
      data,
      isLoading: queryResults.some(q => q.isLoading),
      isError: queryResults.some(q => q.isError),
      errors: queryResults.filter(q => q.isError).map(q => q.error),
      isSuccess: queryResults.every(q => q.isSuccess),
      refetch: async () => await Promise.all(queryResults.map(q => q.refetch())),
    };
  }, [queryResults, queries]);

  return results;
}

// Hook for conditional queries based on user permissions or feature flags
export function useConditionalQuery<T>(
  queryKey: unknown[],
  queryFn: () => Promise<T>,
  conditions: {
    userRole?: string[];
    featureFlag?: string;
    permission?: string;
    customCondition?: () => boolean;
  }
) {
  const enabled = useMemo(() => {
    // Check user role
    if (conditions.userRole) {
      const userRole = typeof window !== 'undefined' ? localStorage.getItem('userRole') : null;
      if (!userRole || !conditions.userRole.includes(userRole)) {
        return false;
      }
    }

    // Check feature flag
    if (conditions.featureFlag) {
      const flags = typeof window !== 'undefined' ? 
        JSON.parse(localStorage.getItem('featureFlags') || '{}') : {};
      if (!flags[conditions.featureFlag]) {
        return false;
      }
    }

    // Check permission
    if (conditions.permission) {
      const permissions = typeof window !== 'undefined' ? 
        JSON.parse(localStorage.getItem('permissions') || '[]') : [];
      if (!permissions.includes(conditions.permission)) {
        return false;
      }
    }

    // Check custom condition
    if (conditions.customCondition && !conditions.customCondition()) {
      return false;
    }

    return true;
  }, [conditions]);

  return useQuery({
    queryKey,
    queryFn,
    enabled,
  });
}


"use client";

import { useQueryClient } from "@tanstack/react-query";
import { useCallback, useEffect, useRef } from "react";

interface QueryBatchConfig {
  maxBatchSize?: number;
  batchDelay?: number;
  enabled?: boolean;
}

// Hook for batching multiple queries into single requests
export function useQueryBatching(config: QueryBatchConfig = {}): {
  batchQuery: (queryKey: unknown[], queryFn: () => Promise<unknown>) => Promise<unknown>;
} {
  const queryClient = useQueryClient();
  const batchQueue = useRef<Map<string, {
    queryKey: unknown[];
    queryFn: () => Promise<unknown>;
    resolve: (data: unknown) => void;
    reject: (error: Error) => void;
  }>>(new Map());
  const batchTimeout = useRef<NodeJS.Timeout | null>(null);

  const maxBatchSize = config.maxBatchSize || 10;
  const batchDelay = config.batchDelay || 50;

  const processBatch = useCallback(async (): Promise<void> => {
    if (batchQueue.current.size === 0) return;

    const batch = Array.from(batchQueue.current.values());
    batchQueue.current.clear();

    // Group by similar query patterns
    const groups = batch.reduce((acc: Record<string, typeof batch>, item) => {
      const pattern = JSON.stringify(item.queryKey).replace(/["'][^"']*["']/g, '""');
      if (!acc[pattern]) acc[pattern] = [];
      acc[pattern]!.push(item);
      return acc;
    }, {} as Record<string, typeof batch>);

    // Process each group
    await Promise.all(
      Object.values(groups).map(async (group: typeof batch) => {
        try {
          // For similar queries, batch them into a single request
          if (group.length > 1) {
            const ids = group.map(item => 
              String(item.queryKey[item.queryKey.length - 1])
            ).filter(id => id && id !== 'undefined');

            const type = group[0]?.queryKey[0];

            if (ids.length > 0 && type) {
              // Batch request
              const res = await fetch('/api/batch', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ ids, type }),
              });
              const batchResult = await res.json() as Record<string, any>;

              // Resolve individual queries
              group.forEach((item, index) => {
                const id = ids[index];
                if (id) {
                  const data = batchResult[id];
                  if (data) {
                    queryClient.setQueryData(item.queryKey, data);
                    item.resolve(data);
                  } else {
                    item.reject(new Error('Data not found in batch'));
                  }
                }
              });
            }
          } else {
            // Single query
            const item = group[0];
            if (item) {
              const data = await item.queryFn();
              queryClient.setQueryData(item.queryKey, data);
              item.resolve(data);
            }
          }
        } catch (error) {
          group.forEach(item => item.reject(error as Error));
        }
      })
    );
  }, [queryClient]);

  const batchQuery = useCallback((
    queryKey: unknown[],
    queryFn: () => Promise<unknown>
  ): Promise<unknown> => {
    return new Promise((resolve, reject) => {
      const key = JSON.stringify(queryKey);
      batchQueue.current.set(key, { queryKey, queryFn, resolve, reject });

      // Clear existing timeout
      if (batchTimeout.current) {
        clearTimeout(batchTimeout.current);
      }

      // Process batch when full or after delay
      if (batchQueue.current.size >= maxBatchSize) {
        void processBatch();
      } else {
        batchTimeout.current = setTimeout(() => {
          void processBatch();
        }, batchDelay);
      }
    });
  }, [processBatch, maxBatchSize, batchDelay]);

  useEffect((): (() => void) => {
    return (): void => {
      if (batchTimeout.current) {
        clearTimeout(batchTimeout.current);
      }
    };
  }, []);

  return { batchQuery };
}

// Hook for query deduplication
export function useQueryDeduplication(): {
  deduplicatedQuery: (queryKey: unknown[], queryFn: () => Promise<unknown>) => Promise<unknown>;
} {
  const activeQueries = useRef<Map<string, Promise<unknown>>>(new Map());

  const deduplicatedQuery = useCallback(async (
    queryKey: unknown[],
    queryFn: () => Promise<unknown>
  ): Promise<unknown> => {
    const key = JSON.stringify(queryKey);

    // Return existing promise if query is already running
    const existing = activeQueries.current.get(key);
    if (existing) {
      return existing;
    }

    // Create new promise and store it
    const promise = queryFn().finally(() => {
      activeQueries.current.delete(key);
    });

    activeQueries.current.set(key, promise);
    return promise;
  }, []);

  return { deduplicatedQuery };
}


"use client";

import { useQueryClient, type Query } from "@tanstack/react-query";
import { useEffect, useCallback, useRef } from "react";

interface QueryMetadata {
  priority: number;
  lastAccessed: number;
  accessCount: number;
  dataSize: number;
  errorCount: number;
}

// Hook for intelligent query lifecycle management
export function useQueryLifecycle(): {
  cleanupStaleQueries: () => void;
  optimizeQueryPriorities: () => void;
  getQueryStats: () => { totalQueries: number; activeQueries: number; highPriorityQueries: number; totalMemoryUsage: number; avgAccessCount: number };
} {
  const queryClient = useQueryClient();
  const queryMetadata = useRef<Map<string, QueryMetadata>>(new Map());

  const updateMetadata = useCallback((queryKey: readonly unknown[], type: 'access' | 'error' | 'success'): void => {
    const key = JSON.stringify(queryKey);
    const existing = queryMetadata.current.get(key) || {
      priority: 1,
      lastAccessed: Date.now(),
      accessCount: 0,
      dataSize: 0,
      errorCount: 0,
    };

    switch (type) {
      case 'access':
        existing.accessCount++;
        existing.lastAccessed = Date.now();
        existing.priority = Math.min(existing.priority + 0.1, 10);
        break;
      case 'error':
        existing.errorCount++;
        existing.priority = Math.max(existing.priority - 0.5, 0.1);
        break;
      case 'success':
        existing.priority = Math.min(existing.priority + 0.2, 10);
        const query = queryClient.getQueryCache().find({ queryKey: queryKey as any });
        if (query?.state.data) {
          existing.dataSize = JSON.stringify(query.state.data).length;
        }
        break;
    }

    queryMetadata.current.set(key, existing);
  }, [queryClient]);

  const cleanupStaleQueries = useCallback((): void => {
    const cache = queryClient.getQueryCache();
    const queries = cache.getAll();
    const now = Date.now();
    const staleThreshold = 30 * 60 * 1000; // 30 minutes

    queries.forEach((query: Query): void => {
      const key = JSON.stringify(query.queryKey);
      const metadata = queryMetadata.current.get(key);

      if (metadata && 
          query.getObserversCount() === 0 && 
          now - metadata.lastAccessed > staleThreshold &&
          metadata.priority < 2) {
        cache.remove(query);
        queryMetadata.current.delete(key);
      }
    });
  }, [queryClient]);

  const optimizeQueryPriorities = useCallback((): void => {
    const cache = queryClient.getQueryCache();
    const queries = cache.getAll();

    queries.forEach((query: Query): void => {
      const key = JSON.stringify(query.queryKey);
      const metadata = queryMetadata.current.get(key);

      if (metadata) {
        // Adjust stale time based on priority and access patterns
        const baseStaleTime = 5 * 60 * 1000; // 5 minutes
        const adjustedStaleTime = baseStaleTime * (metadata.priority / 5);

        if (typeof (query as any).setOptions === 'function') {
          (query as any).setOptions({
            staleTime: Math.max(adjustedStaleTime, 30 * 1000), // Min 30 seconds
            gcTime: adjustedStaleTime * 6, // 6x stale time
          });
        }
      }
    });
  }, [queryClient]);

  // Monitor query events
  useEffect((): (() => void) => {
    const unsubscribe = queryClient.getQueryCache().subscribe((event): void => {
      if (event.type === 'updated') {
        const query = event.query;

        if (query.state.status === 'success') {
          updateMetadata(query.queryKey, 'success');
        } else if (query.state.status === 'error') {
          updateMetadata(query.queryKey, 'error');
        }

        if (query.getObserversCount() > 0) {
          updateMetadata(query.queryKey, 'access');
        }
      }
    });

    return (): void => unsubscribe();
  }, [queryClient, updateMetadata]);

  // Periodic cleanup and optimization
  useEffect((): (() => void) => {
    const cleanupInterval = setInterval(cleanupStaleQueries, 10 * 60 * 1000); // 10 minutes
    const optimizeInterval = setInterval(optimizeQueryPriorities, 5 * 60 * 1000); // 5 minutes

    return (): void => {
      clearInterval(cleanupInterval);
      clearInterval(optimizeInterval);
    };
  }, [cleanupStaleQueries, optimizeQueryPriorities]);

  const getQueryStats = useCallback((): {
    totalQueries: number;
    activeQueries: number;
    highPriorityQueries: number;
    totalMemoryUsage: number;
    avgAccessCount: number;
  } => {
    const cache = queryClient.getQueryCache();
    const queries = cache.getAll();

    return {
      totalQueries: queries.length,
      activeQueries: queries.filter((q: Query) => q.getObserversCount() > 0).length,
      highPriorityQueries: Array.from(queryMetadata.current.values())
        .filter((m: QueryMetadata) => m.priority > 7).length,
      totalMemoryUsage: Array.from(queryMetadata.current.values())
        .reduce((sum: number, m: QueryMetadata) => sum + m.dataSize, 0),
      avgAccessCount: Array.from(queryMetadata.current.values())
        .reduce((sum: number, m: QueryMetadata) => sum + m.accessCount, 0) / (queryMetadata.current.size || 1),
    };
  }, [queryClient]);

  return {
    cleanupStaleQueries,
    optimizeQueryPriorities,
    getQueryStats,
  };
}

